pair B = dir(240);
pair C = dir(0);
pair D = dir(300);
pair E = extension(A, C, B, D);
draw(A--B); draw(A--E); draw(B--E);
draw(Circle( (0,0), 1));
fill(Arc((0,0), C, A)--cycle, gray);
fill(Arc((0,0), B, D)--cycle, gray);
[/asy]

ref_solution:
[asy]
import graph;
size(2inch);
pair A = dir(60);
pair B = dir(240);
pair C = dir(0);
pair D = dir(300);
pair E = extension(A, C, B, D);
fill(Arc((0,0), C, A)--cycle, gray);
fill(Arc((0,0), B, D)--cycle, gray);
draw(A--B); draw(A--E); draw(B--E);
draw(Circle( (0,0), 1));
draw((0,0)--C);
draw((0,0)--D);

dot(A);dot(B);dot(C);dot(D);dot(E);dot((0,0));
